import React, { useState, useEffect } from 'react';
import { ShoppingCart, MapPin, Tag, Box, UserCheck } from 'lucide-react';

const PanelCliente = () => {
  const [ofertas, setOfertas] = useState([]);

  useEffect(() => {
    const locales = JSON.parse(localStorage.getItem('mis-locales') || "[]");
    let todas = [];
    locales.forEach(l => {
      const off = JSON.parse(localStorage.getItem(`ofertas-local-${l.id}`) || "[]");
      todas = [...todas, ...off.map(o => ({ ...o, local: l.nombre, zona: l.zona }))];
    });
    setOfertas(todas);
  }, []);

  return (
    <div style={{ padding: '30px 5%', background: '#f8fafc' }}>
      <h2 style={{ marginBottom: '25px' }}>Mis Ofertas Disponibles</h2>
      <div style={gridEstilo}>
        {ofertas.map(o => (
          <div key={o.id} style={cardEstilo}>
            <div style={badgeAhorro}>-{Math.round(((o.precioViejo - o.precioNuevo)/o.precioViejo)*100)}%</div>
            <img src={o.imagen || 'https://via.placeholder.com/150'} alt={o.producto} style={imgEstilo} />
            
            <div style={{ padding: '15px' }}>
              <h3 style={{ margin: '0 0 10px 0', fontSize: '1.2rem' }}>{o.producto}</h3>
              
              <div style={preciosContainer}>
                <span style={pNuevo}>${o.precioNuevo}</span>
                <span style={pViejo}>${o.precioViejo}</span>
              </div>

              <div style={infoExtra}>
                <div style={tagInfo}><Box size={14} /> Stock: {o.stock}</div>
                <div style={tagInfo}><UserCheck size={14} /> Máx: {o.limitePorCliente}</div>
              </div>

              <p style={localTxt}><MapPin size={14} /> {o.local} ({o.zona})</p>
              
              <button style={btnComprar}>
                <ShoppingCart size={18} /> Reservar Oferta
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

// Estilos rápidos para la demostración
const gridEstilo = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: '25px' };
const cardEstilo = { background: 'white', borderRadius: '20px', overflow: 'hidden', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)', position: 'relative' };
const imgEstilo = { width: '100%', height: '180px', objectFit: 'cover' };
const badgeAhorro = { position: 'absolute', top: '15px', right: '15px', background: '#ef4444', color: 'white', padding: '5px 10px', borderRadius: '8px', fontWeight: 'bold' };
const preciosContainer = { display: 'flex', alignItems: 'baseline', gap: '10px', marginBottom: '15px' };
const pNuevo = { fontSize: '1.8rem', fontWeight: '800', color: '#1e293b' };
const pViejo = { fontSize: '1.1rem', textDecoration: 'line-through', color: '#94a3b8' };
const infoExtra = { display: 'flex', gap: '15px', marginBottom: '15px' };
const tagInfo = { fontSize: '0.8rem', color: '#64748b', display: 'flex', alignItems: 'center', gap: '5px', background: '#f1f5f9', padding: '4px 8px', borderRadius: '6px' };
const localTxt = { fontSize: '0.9rem', color: '#475569', marginBottom: '20px' };
const btnComprar = { width: '100%', padding: '12px', background: '#e67e22', color: 'white', border: 'none', borderRadius: '12px', fontWeight: 'bold', cursor: 'pointer', display: 'flex', justifyContent: 'center', gap: '10px' };

export default PanelCliente;
